import React, { useState, useRef } from 'react';

const theme = {
  bg: '#0a0a0a',
  surface: '#111111',
  surfaceAlt: '#1a1a1a',
  border: '#2a2a2a',
  text: '#fafafa',
  textSecondary: '#a1a1aa',
  textMuted: '#52525b',
  primary: '#8b5cf6',
  blue: '#38bdf8',
  green: '#a3e635',
  red: '#f43f5e',
  yellow: '#fbbf24',
  orange: '#fb923c',
};

const GRID = 3;
const NS = 9;
const NA = 4; // 0=Up 1=Right 2=Down 3=Left
const GOAL = 8;
const TRAP = 4;
const TERMINAL = new Set([GOAL, TRAP]);
const ALPHA = 0.3;
const GAMMA = 0.9;

const ACTION_DIRS = [
  { dx: 0, dy: -1 },
  { dx: 1, dy: 0 },
  { dx: 0, dy: 1 },
  { dx: -1, dy: 0 },
];
const ACTION_LABELS = ['Up', 'Right', 'Down', 'Left'];

function nextState(s, a) {
  const r = Math.floor(s / GRID);
  const c = s % GRID;
  let nr = r, nc = c;
  if (a === 0) nr = Math.max(0, r - 1);
  else if (a === 1) nc = Math.min(2, c + 1);
  else if (a === 2) nr = Math.min(2, r + 1);
  else if (a === 3) nc = Math.max(0, c - 1);
  return nr * GRID + nc;
}

function getReward(ns) {
  if (ns === GOAL) return 1.0;
  if (ns === TRAP) return -1.0;
  return -0.04;
}

function makeQ() {
  return Array.from({ length: NS }, () => new Array(NA).fill(0));
}

function argmax(arr) {
  let best = 0;
  for (let i = 1; i < arr.length; i++) if (arr[i] > arr[best]) best = i;
  return best;
}

function chooseAction(Q, s, eps) {
  if (Math.random() < eps) return Math.floor(Math.random() * NA);
  return argmax(Q[s]);
}

function runInstant(Q, eps, n) {
  const q = Q.map(r => [...r]);
  const nonTerm = [];
  for (let s = 0; s < NS; s++) if (!TERMINAL.has(s)) nonTerm.push(s);
  for (let ep = 0; ep < n; ep++) {
    let s = nonTerm[Math.floor(Math.random() * nonTerm.length)];
    let steps = 0;
    while (!TERMINAL.has(s) && steps < 60) {
      const a = chooseAction(q, s, eps);
      const ns = nextState(s, a);
      const r = getReward(ns);
      const target = TERMINAL.has(ns) ? r : r + GAMMA * Math.max(...q[ns]);
      q[s][a] += ALPHA * (target - q[s][a]);
      s = ns;
      steps++;
    }
  }
  return q;
}

export default function App() {
  const [Q, setQ] = useState(makeQ);
  const [epsilon, setEpsilon] = useState(0.4);
  const [episodeCount, setEpisodeCount] = useState(0);
  const [agentPos, setAgentPos] = useState(null);
  const [path, setPath] = useState([]);
  const [animating, setAnimating] = useState(false);
  const [lastEvent, setLastEvent] = useState(null);
  const cancelRef = useRef(false);

  const nonTerm = [];
  for (let s = 0; s < NS; s++) if (!TERMINAL.has(s)) nonTerm.push(s);

  const runAnimated = async () => {
    if (animating) return;
    setAnimating(true);
    cancelRef.current = false;

    let s = nonTerm[Math.floor(Math.random() * nonTerm.length)];
    const q = Q.map(r => [...r]);
    const episodePath = [s];

    setAgentPos(s);
    setPath([s]);
    setLastEvent(null);

    await new Promise(res => setTimeout(res, 350));

    let steps = 0;
    while (!TERMINAL.has(s) && steps < 25 && !cancelRef.current) {
      const a = chooseAction(q, s, epsilon);
      const ns = nextState(s, a);
      const r = getReward(ns);
      const target = TERMINAL.has(ns) ? r : r + GAMMA * Math.max(...q[ns]);
      q[s][a] += ALPHA * (target - q[s][a]);

      s = ns;
      episodePath.push(s);
      steps++;

      const ev = TERMINAL.has(s)
        ? (s === GOAL ? 'goal' : 'trap')
        : (ACTION_LABELS[a] + ' -> S' + s);

      setAgentPos(s);
      setPath([...episodePath]);
      setQ(q.map(r2 => [...r2]));
      setLastEvent({ text: ev, reward: r, action: ACTION_LABELS[a] });

      await new Promise(res => setTimeout(res, 370));
    }

    setEpisodeCount(c => c + 1);
    await new Promise(res => setTimeout(res, 600));
    if (!cancelRef.current) {
      setAgentPos(null);
      setPath([]);
    }
    setAnimating(false);
  };

  const runBulk = () => {
    if (animating) return;
    const newQ = runInstant(Q, epsilon, 50);
    setQ(newQ);
    setEpisodeCount(c => c + 50);
  };

  const reset = () => {
    cancelRef.current = true;
    setQ(makeQ());
    setEpisodeCount(0);
    setAgentPos(null);
    setPath([]);
    setLastEvent(null);
    setAnimating(false);
  };

  const allQ = Q.flat();
  const qMin = Math.min(...allQ);
  const qMax = Math.max(...allQ);
  const qRange = (qMax - qMin) || 1;

  const CELL = 88;

  const insightText = () => {
    if (episodeCount === 0)
      return 'Q-values are all zero - the agent knows nothing yet. Hit "Run Episode" to watch it explore!';
    if (episodeCount < 5)
      return 'Each step: Q(s,a) += 0.3 * (reward + 0.9 * max_Q(next) - Q(s,a)). Rewards near the goal slowly propagate backward.';
    if (epsilon > 0.6)
      return 'High epsilon = mostly random exploration. Good for early learning, but the policy stays noisy. Try lowering it to see exploitation take over.';
    if (episodeCount > 30)
      return 'Arrows now form a clear path to the star! Q-values propagated the +1 reward backward through the grid. This IS the optimal policy.';
    return 'Arrows show the best action per state (thickest line = highest Q). Watch them orient toward the goal as more episodes run.';
  };

  return (
    <div style={{ background: theme.bg, minHeight: '100vh', fontFamily: "'JetBrains Mono', monospace", display: 'flex', flexDirection: 'column', alignItems: 'center', padding: '14px 10px', color: theme.text }}>
      <div style={{ width: '100%', maxWidth: '560px' }}>

        {/* Header */}
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '12px' }}>
          <div>
            <div style={{ fontSize: '17px', fontWeight: '700' }}>Q-Learning Explorer</div>
            <div style={{ fontSize: '10px', color: theme.textMuted }}>Navigate to the star, avoid the trap</div>
          </div>
          <div style={{ display: 'flex', gap: '7px', alignItems: 'center' }}>
            <button
              onClick={runAnimated}
              disabled={animating}
              style={{ padding: '7px 13px', background: theme.primary, border: 'none', borderRadius: '7px', color: '#fff', fontSize: '11px', fontWeight: '700', cursor: animating ? 'not-allowed' : 'pointer', opacity: animating ? 0.55 : 1, transition: 'opacity 0.2s' }}>
              {animating ? 'Running...' : 'Run Episode'}
            </button>
            <button
              onClick={runBulk}
              disabled={animating}
              style={{ padding: '7px 11px', background: theme.surfaceAlt, border: '1px solid ' + theme.border, borderRadius: '7px', color: theme.textSecondary, fontSize: '11px', cursor: animating ? 'not-allowed' : 'pointer', opacity: animating ? 0.55 : 1 }}>
              +50
            </button>
            <button
              onClick={reset}
              style={{ padding: '7px 11px', background: theme.surfaceAlt, border: '1px solid ' + theme.border, borderRadius: '7px', color: theme.textMuted, fontSize: '11px', cursor: 'pointer' }}>
              Reset
            </button>
          </div>
        </div>

        {/* Epsilon slider */}
        <div style={{ background: theme.surface, borderRadius: '9px', padding: '9px 13px', marginBottom: '10px', display: 'flex', alignItems: 'center', gap: '10px', border: '1px solid ' + theme.border }}>
          <span style={{ fontSize: '10px', color: theme.textMuted, whiteSpace: 'nowrap' }}>epsilon</span>
          <input
            type="range" min="0" max="1" step="0.05" value={epsilon}
            onChange={e => setEpsilon(parseFloat(e.target.value))}
            style={{ flex: 1, accentColor: theme.primary, cursor: 'pointer' }} />
          <span style={{ fontSize: '13px', fontWeight: '700', color: epsilon > 0.5 ? theme.orange : theme.blue, minWidth: '32px', textAlign: 'right' }}>
            {epsilon.toFixed(2)}
          </span>
          <span style={{ fontSize: '9px', color: theme.textMuted, minWidth: '48px' }}>
            {epsilon < 0.15 ? 'Exploit' : epsilon > 0.55 ? 'Explore' : 'Balanced'}
          </span>
        </div>

        {/* Grid */}
        <div style={{ background: theme.surface, borderRadius: '12px', padding: '14px', marginBottom: '10px', border: '1px solid ' + theme.border }}>
          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(3, ' + CELL + 'px)', gap: '6px', margin: '0 auto', width: 'fit-content' }}>
            {Array.from({ length: NS }, (_, state) => {
              const isGoal = state === GOAL;
              const isTrap = state === TRAP;
              const isAgent = state === agentPos;
              const inPath = path.includes(state);
              const isTerm = TERMINAL.has(state);
              const best = argmax(Q[state]);
              const bestQ = Q[state][best];

              let bg = theme.surfaceAlt;
              if (isGoal) bg = '#0c2318';
              else if (isTrap) bg = '#280c14';
              else if (isAgent) bg = '#1a1040';
              else if (inPath && !isTerm) bg = '#14102a';

              let borderCol = theme.border;
              if (isGoal) borderCol = theme.green;
              else if (isTrap) borderCol = theme.red;
              else if (isAgent) borderCol = theme.primary;
              else if (inPath && !isTerm) borderCol = '#4a3a8a';

              return (
                <div key={state} style={{
                  width: CELL, height: CELL,
                  background: bg,
                  border: '2px solid ' + borderCol,
                  borderRadius: '8px',
                  position: 'relative',
                  display: 'flex', flexDirection: 'column',
                  alignItems: 'center', justifyContent: 'center',
                  transition: 'all 0.22s ease',
                  overflow: 'hidden',
                }}>
                  <div style={{ fontSize: '8px', color: theme.textMuted, position: 'absolute', top: '3px', left: '5px' }}>S{state}</div>

                  {isGoal && (
                    <div style={{ textAlign: 'center' }}>
                      <div style={{ fontSize: '22px', lineHeight: 1 }}>★</div>
                      <div style={{ fontSize: '9px', color: theme.green, fontWeight: '700', marginTop: '2px' }}>+1 Goal</div>
                    </div>
                  )}

                  {isTrap && (
                    <div style={{ textAlign: 'center' }}>
                      <div style={{ fontSize: '22px', lineHeight: 1, color: theme.red }}>X</div>
                      <div style={{ fontSize: '9px', color: theme.red, fontWeight: '700', marginTop: '2px' }}>-1 Trap</div>
                    </div>
                  )}

                  {!isTerm && (
                    <>
                      {isAgent ? (
                        <div style={{ fontSize: '22px', color: theme.primary, lineHeight: 1, zIndex: 2 }}>●</div>
                      ) : (
                        <svg width={CELL - 12} height={CELL - 12} style={{ position: 'absolute', top: 6, left: 6 }}>
                          {ACTION_DIRS.map((dir, a) => {
                            const qv = Q[state][a];
                            const norm = (qv - qMin) / qRange;
                            const cx = (CELL - 12) / 2;
                            const cy = (CELL - 12) / 2;
                            const minLen = 8, maxLen = 26;
                            const len = minLen + Math.abs(norm) * (maxLen - minLen);
                            const isBest = a === best && Math.abs(bestQ) > 0.005;
                            const ex = cx + dir.dx * len;
                            const ey = cy + dir.dy * len;
                            let col = theme.textMuted;
                            if (isBest) col = qv > 0 ? theme.green : theme.red;
                            const strokeW = isBest ? 2.8 : 1.2;
                            const op = 0.15 + Math.abs(norm) * 0.85;
                            // arrowhead
                            const ang = Math.atan2(dir.dy, dir.dx);
                            const aw = isBest ? 4 : 2.5;
                            const ax1 = ex - aw * Math.cos(ang - 0.5);
                            const ay1 = ey - aw * Math.sin(ang - 0.5);
                            const ax2 = ex - aw * Math.cos(ang + 0.5);
                            const ay2 = ey - aw * Math.sin(ang + 0.5);
                            return (
                              <g key={a} opacity={op}>
                                <line x1={cx} y1={cy} x2={ex} y2={ey} stroke={col} strokeWidth={strokeW} />
                                <polygon points={ex + ',' + ey + ' ' + ax1 + ',' + ay1 + ' ' + ax2 + ',' + ay2} fill={col} />
                              </g>
                            );
                          })}
                        </svg>
                      )}
                      <div style={{ fontSize: '8px', color: bestQ > 0.01 ? theme.green : bestQ < -0.01 ? theme.red : theme.textMuted, position: 'absolute', bottom: '3px', right: '5px', fontWeight: '600' }}>
                        {bestQ.toFixed(2)}
                      </div>
                    </>
                  )}
                </div>
              );
            })}
          </div>

          {/* Legend */}
          <div style={{ display: 'flex', gap: '14px', justifyContent: 'center', marginTop: '10px', fontSize: '9px', color: theme.textMuted, flexWrap: 'wrap' }}>
            <span><span style={{ color: theme.primary }}>●</span> Agent</span>
            <span><span style={{ color: theme.green }}>&#8594;</span> Best action (+Q)</span>
            <span><span style={{ color: theme.red }}>&#8594;</span> Best action (-Q)</span>
            <span style={{ color: theme.textMuted }}>&#8594; Other actions</span>
          </div>
        </div>

        {/* Stats row */}
        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr 1fr 1fr', gap: '7px', marginBottom: '10px' }}>
          {[
            { label: 'Episodes', value: episodeCount, color: theme.primary },
            { label: 'alpha', value: ALPHA.toFixed(1), color: theme.blue },
            { label: 'gamma', value: GAMMA.toFixed(1), color: theme.yellow },
            { label: 'epsilon', value: epsilon.toFixed(2), color: epsilon > 0.5 ? theme.orange : theme.blue },
          ].map(({ label, value, color }) => (
            <div key={label} style={{ background: theme.surface, borderRadius: '8px', padding: '8px 6px', textAlign: 'center', border: '1px solid ' + theme.border }}>
              <div style={{ fontSize: '16px', fontWeight: '700', color }}>{value}</div>
              <div style={{ fontSize: '8px', color: theme.textMuted, marginTop: '1px' }}>{label}</div>
            </div>
          ))}
        </div>

        {/* Last event */}
        {lastEvent && (
          <div style={{
            background: lastEvent.text === 'goal' ? '#0c2318' : lastEvent.text === 'trap' ? '#280c14' : theme.surfaceAlt,
            border: '1px solid ' + (lastEvent.text === 'goal' ? theme.green : lastEvent.text === 'trap' ? theme.red : theme.border),
            borderRadius: '8px', padding: '7px 12px', marginBottom: '10px',
            display: 'flex', justifyContent: 'space-between', alignItems: 'center',
            fontSize: '10px', color: theme.textSecondary,
          }}>
            <span>
              Action: <span style={{ color: theme.blue, fontWeight: '700' }}>{lastEvent.action}</span>
            </span>
            <span>
              Reward: <span style={{ color: lastEvent.reward > 0 ? theme.green : lastEvent.reward < 0 ? theme.red : theme.textSecondary, fontWeight: '700' }}>
                {lastEvent.reward > 0 ? '+' : ''}{lastEvent.reward.toFixed(2)}
              </span>
            </span>
            <span>
              {lastEvent.text === 'goal'
                ? <span style={{ color: theme.green, fontWeight: '700' }}>Reached Goal!</span>
                : lastEvent.text === 'trap'
                ? <span style={{ color: theme.red, fontWeight: '700' }}>Hit Trap!</span>
                : <span>Moved to S{lastEvent.text.split('S')[1]}</span>}
            </span>
          </div>
        )}

        {/* Update rule display */}
        <div style={{ background: theme.surfaceAlt, borderRadius: '8px', padding: '8px 12px', marginBottom: '10px', fontSize: '10px', color: theme.textMuted, border: '1px solid ' + theme.border }}>
          <span style={{ color: theme.textSecondary }}>Update: </span>
          <span style={{ color: theme.blue }}>Q(s,a)</span>
          <span> += </span>
          <span style={{ color: theme.yellow }}>{ALPHA}</span>
          <span> * (r + </span>
          <span style={{ color: theme.orange }}>{GAMMA}</span>
          <span> * max_a' Q(s') - </span>
          <span style={{ color: theme.blue }}>Q(s,a)</span>
          <span>)</span>
        </div>

        {/* Key Insight */}
        <div style={{ background: theme.surfaceAlt, borderRadius: '8px', padding: '10px 13px', fontSize: '11px', color: theme.textSecondary, borderLeft: '3px solid ' + theme.primary }}>
          <span style={{ color: theme.primary, fontWeight: '700' }}>Insight: </span>
          {insightText()}
        </div>

      </div>
    </div>
  );
}
